/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const M = grid.length;
    const N = grid[0].length;
    // Maximum possible XOR value is 1023 (2^10 - 1)
    const S = 1024;

    // dp[i][j] will be an array of size S, where dp[i][j][k] is true 
    // if XOR sum k is achievable at cell (i, j).
    // Initialize M rows, each containing N cells, each cell holding a boolean array of size S.
    const dp = Array(M).fill(0).map(() => 
        Array(N).fill(0).map(() => 
            Array(S).fill(false)
        )
    );

    // Base case: Start at (0, 0)
    dp[0][0][grid[0][0]] = true;

    // Fill the DP table
    for (let i = 0; i < M; i++) {
        for (let j = 0; j < N; j++) {
            const G = grid[i][j];

            if (i === 0 && j === 0) {
                // Already handled the base case
                continue;
            }

            // 1. Try coming from above (i-1, j)
            if (i > 0) {
                const prevRow = i - 1;
                for (let k = 0; k < S; k++) {
                    if (dp[prevRow][j][k]) {
                        const newXor = k ^ G;
                        dp[i][j][newXor] = true;
                    }
                }
            }

            // 2. Try coming from left (i, j-1)
            if (j > 0) {
                const prevCol = j - 1;
                for (let k = 0; k < S; k++) {
                    if (dp[i][prevCol][k]) {
                        const newXor = k ^ G;
                        dp[i][j][newXor] = true;
                    }
                }
            }
        }
    }

    // Find the minimum achievable XOR sum at the target cell (M-1, N-1)
    const targetDP = dp[M - 1][N - 1];
    for (let k = 0; k < S; k++) {
        if (targetDP[k]) {
            return k;
        }
    }

    // Should not happen given the constraints (path always exists)
    return -1; 
}

